('verbal', 'inference', '{6-8}', 1.0, 1.5, 0.20, '{"stem": "A news article reports that a company laid off 30% of workers, then its stock price rose. What can be inferred?", "type": "inference", "options": [{"text": "Workers were unproductive"}, {"text": "Investors valued cost reduction"}, {"text": "The company is failing"}, {"text": "Stock prices always rise after layoffs"}], "correct_index": 1}'),
('verbal', 'reading_comprehension', '{6-8}', 1.0, 1.5, 0.20, '{"stem": "The author uses the phrase ''a double-edged sword'' to describe technology. This means technology:", "type": "figurative_language", "options": [{"text": "Is dangerous"}, {"text": "Has both benefits and drawbacks"}, {"text": "Is medieval"}, {"text": "Should be avoided"}], "correct_index": 1}'),
('verbal', 'inference', '{6-8}', 1.5, 1.6, 0.15, '{"stem": "A historian writes: ''The treaty, while celebrated at the time, planted the seeds of future conflict.'' The historian believes:", "type": "inference", "options": [{"text": "The treaty was entirely successful"}, {"text": "The treaty eventually led to problems"}, {"text": "Treaties never work"}, {"text": "The celebration was premature but the treaty worked"}], "correct_index": 1}'),
('verbal', 'vocabulary', '{6-8}', 1.5, 1.7, 0.15, '{"stem": "What does \"pragmatic\" mean?", "type": "definition", "options": [{"text": "Idealistic"}, {"text": "Dealing with things practically"}, {"text": "Dramatic"}, {"text": "Ancient"}], "correct_index": 1}'),
('verbal', 'reading_comprehension', '{6-8}', 2.0, 1.8, 0.15, '{"stem": "An author writes about poverty using statistics AND a personal story. Why use both approaches?", "type": "rhetoric", "options": [{"text": "To make the writing longer"}, {"text": "Statistics prove the point; the story makes it emotionally real"}, {"text": "One approach was not enough pages"}, {"text": "The personal story replaces the statistics"}], "correct_index": 1}'),
('verbal', 'inference', '{6-8}', 2.0, 1.8, 0.15, '{"stem": "Two scientists publish opposing conclusions from the same data. What is the BEST explanation?", "type": "critical_thinking", "options": [{"text": "One scientist is wrong"}, {"text": "The data is flawed"}, {"text": "They used different analytical frameworks or assumptions"}, {"text": "Science cannot answer this question"}], "correct_index": 2}'),
('verbal', 'vocabulary', '{6-8}', 2.5, 2.0, 0.15, '{"stem": "''Juxtaposition'' in literature refers to:", "type": "definition", "options": [{"text": "Placing contrasting elements side by side"}, {"text": "Writing from multiple perspectives"}, {"text": "Using legal language in fiction"}, {"text": "Breaking the fourth wall"}], "correct_index": 0}'),
('verbal', 'reading_comprehension', '{6-8}', 2.5, 1.9, 0.15, '{"stem": "A satirist writes ''The committee, in its infinite wisdom, decided to solve homelessness by painting the park benches an unpleasant color.'' The tone is:", "type": "tone_analysis", "options": [{"text": "Sincere and praising"}, {"text": "Sarcastic and critical"}, {"text": "Neutral and informative"}, {"text": "Sympathetic and sad"}], "correct_index": 1}'),
('verbal', 'inference', '{6-8}', 3.0, 2.0, 0.15, '{"stem": "An author argues that standardized tests measure socioeconomic status more than intelligence. What would MOST weaken this argument?", "type": "critical_thinking", "options": [{"text": "Many wealthy students score poorly"}, {"text": "Test scores correlate with family income"}, {"text": "Students from all backgrounds score similarly when given equal test prep"}, {"text": "Test prep companies exist"}], "correct_index": 0}');
